import { useEffect, useState } from "react";
import { Field, Form } from "react-final-form";
import { Link } from "react-router-dom";
import AlertDismissible from "../../../common/AlertDismissible";
import { InputField } from "../../../common/InputText";
import loginBanner from "../../assets/images/login-banner.png";
import AuthService from "../../services/auth.service";

function ForgotPassword() {
  const required = `Required`;
  const [message, setMessage] = useState();
  const [isLoading, setIsLoading] = useState(false);
  const [forgotStatus, setForgotStatus] = useState();
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  useEffect(() => {
    document.body.classList.add("account-page");
    return () => {
      document.body.classList.remove("account-page");
    };
  }, []);

  const onSubmit = async (values) => {
    setForgotStatus(false);
    setIsLoading(true);
    console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
    // await sleep(1500);
    const response = await AuthService.forgotPassword(values.email);
    setIsLoading(false);

    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }

    setForgotStatus(!!response.success && response.success);
  };

  const validate = async (values) => {
    const errors = {};
    if (!values.email) {
      errors.email = required;
    } else if (
      !values.email
        .toLowerCase()
        .match(
          /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
        )
    ) {
      errors.email = "Invalid Email format!";
    }
    return errors;
  };

  return (
    <div className="content">
      <div className="container-fluid">
        <div className="row justify-content-center">
          <div className="col-md-8">
            <div className="account-content">
              {forgotStatus ? (
                <AlertDismissible
                  type={"success"}
                  boldMsg={"Success"}
                  msg={"A reset link was sent to you, please check your inbox"}
                />
              ) : (
                ""
              )}
              <div className="row align-items-center justify-content-center">
                <div className="col-md-7 col-lg-6 login-left">
                  <img
                    src={loginBanner}
                    className="img-fluid"
                    alt="Login Banner"
                  />
                </div>
                <div className="col-md-12 col-lg-6 login-right">
                  <div className="login-header">
                    <h3>Forgot Password?</h3>
                    <p className="small text-muted">
                      Enter your email to get a password reset link
                    </p>
                  </div>
                  <Form
                    validate={validate}
                    onSubmit={onSubmit}
                    render={({
                      handleSubmit,
                      submitError,
                      form,
                      submitting,
                      pristine,
                      values,
                    }) => (
                      <form
                        onSubmit={handleSubmit}
                        className="needs-validation"
                        noValidate
                      >
                        <div className="invalid-feedback d-block mb-2">
                          {message}
                        </div>
                        <div
                          className={`form-group form-focus mt-4 ${
                            values?.email?.length > 0 ? "focused" : ""
                          }`}
                        >
                          <Field
                            name="email"
                            className="form-control floating"
                            label="Email"
                            type="text"
                            label_type="focus_label"
                            component={InputField}
                          />
                        </div>
                        <div className="text-right">
                          <Link to="/login" className="forgot-link">
                            Remember your password?{" "}
                          </Link>
                        </div>
                        <button
                          className="btn btn-primary btn-block btn-lg login-btn"
                          type="submit"
                          disabled={isLoading}
                        >
                          {!isLoading ? `Reset Password` : ""}
                          {isLoading && (
                            <span className="spinner-border spinner-border-sm mb-1"></span>
                          )}
                        </button>
                      </form>
                    )}
                  />
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ForgotPassword;
